import React, { useState, useEffect } from 'react';
import axios from 'axios';
import API_BASE from '../config';
import { sendRoundDataToCaptivate } from '../utils/sendRoundDataToCaptivate';
import gameDataController from '../captivateDataController';

function ProducerDashboard() {
  const [player1Email, setPlayer1Email] = useState('');
  const [player2Email, setPlayer2Email] = useState('');
  const [player1Decks, setPlayer1Decks] = useState([]);
  const [player2Decks, setPlayer2Decks] = useState([]);
  const [selectedDeck1, setSelectedDeck1] = useState(null);
  const [selectedDeck2, setSelectedDeck2] = useState(null);
  const [gameId, setGameId] = useState('');
  const [loadGameId, setLoadGameId] = useState('');
  const [gameData, setGameData] = useState(null);

  const fetchDecks = async (email, setDecks) => {
    try {
      const res = await axios.get(`${API_BASE}/api/decks?email=${email}`);
      setDecks(res.data);
    } catch (err) {
      console.error('Error fetching decks:', err);
      alert('Failed to fetch decks');
    }
  };

  const handleStartGame = async () => {
    if (!selectedDeck1 || !selectedDeck2) {
      alert('Select a deck for both players');
      return;
    }

    try {
      const res = await axios.post(`${API_BASE}/api/games`, {
        player1: { email: player1Email, deck: selectedDeck1.cards },
        player2: { email: player2Email, deck: selectedDeck2.cards }
      });
      setGameId(res.data._id);
      alert(`Game started! Game ID: ${res.data._id}`);
    } catch (err) {
      console.error('Error starting game:', err);
      alert('Failed to start game');
    }
  };

  const handleStartRound = async () => {
    try {
      const res = await axios.post(`${API_BASE}/api/games/${gameId}/start-round`);
      alert('Round started!');
      // Fetch and update Captivate data
      fetchGameStateForCaptivate(gameId);
    } catch (err) {
      console.error('Error starting round:', err);
      alert('Failed to start round');
    }
  };

  const handleLoadGame = async () => {
    if (!loadGameId) {
      alert('Please enter a Game ID to load.');
      return;
    }
    try {
      const res = await axios.get(`${API_BASE}/api/games/${loadGameId}`);
      setGameId(loadGameId);
      alert(`Game loaded! Game ID: ${loadGameId}`);
      // Auto-populate player info
      const game = res.data;
      if (game.player1 && game.player2) {
        setPlayer1Email(game.player1.email || '');
        setPlayer2Email(game.player2.email || '');
        // Fetch decks for both players and auto-select the correct deck
        if (game.player1.deck && game.player1.email) {
          const decks1 = await axios.get(`${API_BASE}/api/decks?email=${game.player1.email}`);
          setPlayer1Decks(decks1.data);
          // Try to find the deck by _id or name
          const foundDeck1 = decks1.data.find(
            d => d._id === game.player1.deck._id || d.name === game.player1.deck.name
          );
          setSelectedDeck1(foundDeck1 || null);
        }
        if (game.player2.deck && game.player2.email) {
          const decks2 = await axios.get(`${API_BASE}/api/decks?email=${game.player2.email}`);
          setPlayer2Decks(decks2.data);
          const foundDeck2 = decks2.data.find(
            d => d._id === game.player2.deck._id || d.name === game.player2.deck.name
          );
          setSelectedDeck2(foundDeck2 || null);
        }
      }
    } catch (err) {
      console.error('Error loading game:', err);
      alert('Failed to load game. Please check the Game ID.');
    }
  };

  // Fetch game state for Captivate
  const fetchGameStateForCaptivate = async (gameId) => {
    try {
      const res = await axios.get(`${API_BASE}/api/games/${gameId}`);
      setGameData(res.data);
      // Extract current round and cards
      const roundIndex = res.data.currentRound ? res.data.currentRound - 1 : 0;
      const round = res.data.rounds?.[roundIndex] || {};
      const gameStateForCaptivate = {
        player1: {
          name: res.data.player1?.name || res.data.player1?.email || '',
          handle: res.data.player1?.handle || res.data.player1?.email || '',
          avatarUrl: res.data.player1?.avatarUrl || '',
          aura: res.data.player1?.score?.aura || 0,
          skill: res.data.player1?.score?.skill || 0,
          stamina: res.data.player1?.score?.stamina || 0,
        },
        player2: {
          name: res.data.player2?.name || res.data.player2?.email || '',
          handle: res.data.player2?.handle || res.data.player2?.email || '',
          avatarUrl: res.data.player2?.avatarUrl || '',
          aura: res.data.player2?.score?.aura || 0,
          skill: res.data.player2?.score?.skill || 0,
          stamina: res.data.player2?.score?.stamina || 0,
        },
        card1: round.C1 || {},
        card2: round.C2 || {},
        winner: round.winner ? (round.winner === 'P1' ? round.C1 : round.C2) : {},
      };
      gameDataController.updateFromGameState(gameStateForCaptivate);
    } catch (err) {
      console.error('Error fetching game state for Captivate:', err);
    }
  };

  // Add a useEffect to auto-fetch game state for Captivate when gameId changes
  useEffect(() => {
    if (gameId) {
      fetchGameStateForCaptivate(gameId);
      // Optionally, poll for updates every few seconds
      const interval = setInterval(() => fetchGameStateForCaptivate(gameId), 3000);
      return () => clearInterval(interval);
    }
  }, [gameId]);

  return (
    <div>
      <h2>Game Setup</h2>

      <div>
        <h3>Player 1</h3>
        <input
          type="email"
          placeholder="Enter Player 1 Email"
          value={player1Email}
          onChange={(e) => setPlayer1Email(e.target.value)}
        />
        <button onClick={() => fetchDecks(player1Email, setPlayer1Decks)}>Load Decks</button>
        <select onChange={(e) => setSelectedDeck1(player1Decks[e.target.value])}>
          <option value="">Select Deck</option>
          {player1Decks.map((deck, index) => (
            <option key={deck._id} value={index}>
              {deck.name}
            </option>
          ))}
        </select>
      </div>

      <div>
        <h3>Player 2</h3>
        <input
          type="email"
          placeholder="Enter Player 2 Email"
          value={player2Email}
          onChange={(e) => setPlayer2Email(e.target.value)}
        />
        <button onClick={() => fetchDecks(player2Email, setPlayer2Decks)}>Load Decks</button>
        <select onChange={(e) => setSelectedDeck2(player2Decks[e.target.value])}>
          <option value="">Select Deck</option>
          {player2Decks.map((deck, index) => (
            <option key={deck._id} value={index}>
              {deck.name}
            </option>
          ))}
        </select>
      </div>

      <button onClick={handleStartGame}>Start Game</button>

      {gameId && (
        <div>
          <p><strong>Game ID:</strong> {gameId}</p>
          <button onClick={handleStartRound}>Start Round</button>
        </div>
      )}

      <div>
        <h3>Load Existing Game</h3>
        <input
          type="text"
          placeholder="Enter Game ID"
          value={loadGameId}
          onChange={(e) => setLoadGameId(e.target.value)}
        />
        <button onClick={handleLoadGame}>Load Game</button>
      </div>
    </div>
  );
}

export default ProducerDashboard;
